# Ищем каждую категорию и добавляем fullDescription
for slug, desc_text in descriptions.items():
    # Экранируем кавычки в описании
    escaped_desc = desc_text.replace('"', '\\"')

    # Ищем строку метаDesc этой категории
    pattern = rf'(\{{ slug: "{slug}",.*?, metaDesc: "[^"]*")'

    def replacer(match):
        return match.group(1) + f', fullDescription: "{escaped_desc}"'

    content = re.sub(pattern, replacer, content, flags=re.DOTALL)

# Сохраняем
with open('src/config/company.ts', 'w', encoding='utf-8') as f:
    f.write(content)

print("✅ Добавлены fullDescription для всех категорий")
